// ── Authenticate ─────────────────────────────────────────────────────────
const headers = $('Ingest Webhook').first().json.headers || {};
const authHeader = headers.authorization || headers.Authorization || '';
const token = authHeader.replace(/^Bearer\s+/i, '').trim();
const expectedToken = $vars.KB_INGEST_TOKEN || '';
if (expectedToken && token !== expectedToken) {
  throw new Error('401 Unauthorized: invalid Bearer token');
}

// ── Extract form fields ───────────────────────────────────────────────────
const body = $('Ingest Webhook').first().json.body || $('Ingest Webhook').first().json;
const chatId = parseInt(body.chat_id || '0') || 0;
const filename = (body.filename || 'upload.bin').replace(/[^a-zA-Z0-9._-]/g, '_');
const mime = body.mime || 'application/octet-stream';

// ── Write binary to /tmp ──────────────────────────────────────────────────
const fs = require('fs');
const crypto = require('crypto');
const binary = $('Ingest Webhook').first().binary?.file;
if (!binary) throw new Error('No file received — multipart field must be named "file"');
const buf = Buffer.from(binary.data, 'base64');
const sha256 = crypto.createHash('sha256').update(buf).digest('hex');
const tmpPath = `/tmp/kb_${sha256}`;
fs.writeFileSync(tmpPath, buf);

return [{ json: {
  chat_id: chatId,
  filename,
  mime,
  sha256,
  tmpPath,
  fileSize: buf.length,
  startMs: Date.now()
}}];

const prev = $('Auth and Write File').first().json;
const docRow = items[0].json;
return [{ json: { ...prev, doc_id: docRow.doc_id, is_new: docRow.is_new } }];

// Parse docling output
const rawStdout = items[0].json.stdout || items[0].json;
let parsed;
try {
  parsed = JSON.parse(typeof rawStdout === 'string' ? rawStdout.trim() : JSON.stringify(rawStdout));
} catch (e) {
  throw new Error('Docling output parse failed. stdout: ' + String(rawStdout).substring(0, 400));
}
if (!parsed.ok) throw new Error('Docling error: ' + parsed.error);

const meta = $('Attach Doc ID').first().json;
const CHUNK_SIZE = parseInt($vars.KB_CHUNK_SIZE || '512');
const OVERLAP    = parseInt($vars.KB_CHUNK_OVERLAP || '50');

// Clean up temp file
try { require('fs').unlinkSync(meta.tmpPath); } catch(_) {}

// Build chunks
const chunks = [];
for (const page of (parsed.pages || [])) {
  const text = (page.text || '').trim();
  if (!text) continue;
  let start = 0;
  while (start < text.length) {
    const end = Math.min(start + CHUNK_SIZE, text.length);
    const chunkText = text.slice(start, end).trim();
    if (chunkText.length > 20) {
      chunks.push({
        doc_id:     meta.doc_id,
        chat_id:    meta.chat_id,
        sha256:     meta.sha256,
        filename:   meta.filename,
        startMs:    meta.startMs,
        section:    (page.section || '').substring(0, 200),
        text:       chunkText,
        chunk_idx:  chunks.length,
        totalChunks: 0  // filled after loop
      });
    }
    start = end - OVERLAP;
    if (start >= end) break;
  }
}

// Attach total count
chunks.forEach(c => { c.totalChunks = chunks.length; });

if (chunks.length === 0) throw new Error('No text chunks extracted from document');

return chunks.map(c => ({ json: c }));
